def generate_totp_secret(length=16):
    return ''.join([chr(random.randint(33, 126)) for _ in range(length)])

def encode_base32(data):
    data += b'======='
    padding = ord(data[-1]) * 8 if (ord(data[-1]) % 4) else 0
    data = bytearray(data)
    data[-padding:] = [0] * padding
    return base64.b32encode(data).decode().upper()

def create_totp_secret_qr(secret):
    url = pyqrcode.create(f"otpauth://totp/{username}?secret={secret}&issuer=OurMFASystem")
    url.png('totp.png', scale=6)

def validate_totp_code(secret, code):
    expected_code = int.from_bytes(
        hmac.new(secret.encode(), 
                 (datetime.utcnow() + timedelta(seconds=-30)).isocalendar()[1:].encode(),
                 digestmod=hashlib.sha1).digest()[:4], byteorder='big')
    return (expected_code == int(code))

